class Solution:
    def findMinimumTime(self, strength, k):
        # independent re-derivation: try every explicit ordering of the locks
        import itertools
        best = None
        for perm in itertools.permutations(range(len(strength))):
            x = 1
            total = 0
            for idx in perm:
                total += -(-strength[idx] // x)
                x += k
            if best is None or total < best:
                best = total
        return best

