class Solution:
    def findMinimumTime(self, strength, k):
        n = len(strength)
        full = 1 << n
        INF = float('inf')
        dp = [INF] * full
        dp[0] = 0
        for mask in range(full):
            if dp[mask] == INF:
                continue
            cnt = bin(mask).count('1')
            x = 1 + cnt * k
            for i in range(n):
                if not (mask >> i) & 1:
                    t = -(-strength[i] // x)
                    nmask = mask | (1 << i)
                    if dp[mask] + t < dp[nmask]:
                        dp[nmask] = dp[mask] + t
        return dp[full - 1]

