var findMinimumTime = function(strength, k) {
    const n = strength.length;
    const full = 1 << n;
    const dp = new Array(full).fill(Infinity);
    dp[0] = 0;
    for (let mask = 0; mask < full; mask++) {
        if (dp[mask] === Infinity) continue;
        let cnt = 0;
        for (let i = 0; i < n; i++) if (mask & (1 << i)) cnt++;
        const x = 1 + cnt * k;
        for (let i = 0; i < n; i++) {
            if (!(mask & (1 << i))) {
                const t = Math.ceil(strength[i] / x);
                const nmask = mask | (1 << i);
                if (dp[mask] + t < dp[nmask]) dp[nmask] = dp[mask] + t;
            }
        }
    }
    return dp[full - 1];
};
